cd /tmp/sv-ba6b26ba37f948988126cfeabea38fa7/simple-solution && dotnet list package --format json 2>/dev/null | python3 -c "import sys,json; data=json.load(sys.stdin); json.dump(data,open('after-cpm-packages.json','w'),indent=2)" && python3 -c "
import json
baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(name, {})[pkg['id']] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg)
        av = a.get(proj,{}).get(pkg)
        if bv != av:
            print(f'CHANGED: {proj}/{pkg}: {bv} -> {av}')
            changes = True
if not changes:
    print('All packages resolve identically to baseline.')
"

